UPDATE kb_chunk
parent_id = #{parentId}, content = #{content}, content_hash = #{contentHash}, content_vector = #{contentVector}::vector, token_count = #{tokenCount}, status = #{status}, metadata = #{metadata}::jsonb,
WHERE id = #{id}

UPDATE kb_chunk
SET content = #{content}, token_count = #{tokenCount}
WHERE id = #{id}

UPDATE kb_chunk SET content_vector = v.vector::vector, status = v.status FROM (
SELECT #{c.id}::bigint AS id, #{c.contentVector}::text AS vector, #{c.status}::text AS status
) AS v WHERE kb_chunk.id = v.id

UPDATE kb_chunk SET status = #{status}
WHERE id IN

    #{id}

mapper.select:
SELECT 
FROM kb_chunk
WHERE doc_id = #{docId}
  AND chunk_type = 'child'

      AND status = #{status}

ORDER BY id

SELECT id, parent_id, content, doc_id, kb_id, metadata::text AS metadata FROM kb_chunk WHERE chunk_type = 'child' AND status = 'active' AND content_vector IS NOT NULL
AND kb_id = #{kbId}
ORDER BY content_vector <=> #{vectorStr}::vector LIMIT #{topK}

SELECT id, parent_id, content, doc_id, kb_id, metadata::text AS metadata, ts_rank(tsv, websearch_to_tsquery('zh_cn', #{query})) AS rank FROM kb_chunk WHERE chunk_type = 'child' AND status = 'active' AND tsv @@ websearch_to_tsquery('zh_cn', #{query})
AND kb_id = #{kbId}
ORDER BY rank DESC LIMIT #{topK}
